import React, { useState, useEffect } from "react";
import { useNavigate, useLocation } from "react-router-dom";
import "./AdminDashboard.module.css"; // Import your CSS for styling
import { Doughnut, Line } from 'react-chartjs-2'; // Import required chart types
import chatbotImage from '../images/img-1.webp';
import mapIntegrationImage from '../images/img-2.webp';
import ukDataImage from '../images/img-3.jpg';

const AdminDashboard = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const [planType, setPlanType] = useState("month");
  const [selectedOption, setSelectedOption] = useState("Overview");
  const [userEmail] = useState("karthik@gmail.com");
  const [numUsers] = useState(33);
  const [purchasedFeatures, setPurchasedFeatures] = useState([]);
  const isChatbotPage = location.pathname === "/chatbot";
  const [popupMessage, setPopupMessage] = useState("");
  
  // Sample data for the charts and user statistics
  const featureUsage = {
    chatbot: 15,
    mapIntegration: 55,
    ukData: 30
  };

  // Chart.js data for pie chart
  const pieChartData = {
    labels: ["Chatbot", "Chatbot with Map Interaction", "UK Data Overlay"],
    datasets: [
      {
        data: [featureUsage.chatbot, featureUsage.mapIntegration, featureUsage.ukData],
        backgroundColor: ["#4caf50", "#ff9800", "#f44336"],
        hoverBackgroundColor: ["#388e3c", "#f57c00", "#d32f2f"]
      }
    ]
  };

  // Line chart data for usage stats
  const lineChartData = {
    labels: ['January', 'February', 'March', 'April', 'May', 'June', 'July'],
    datasets: [
      {
        label: 'Chatbot Usage',
        data: [10, 15, 12, 18, 25, 30, 40],
        borderColor: '#4caf50',
        fill: false
      },
      {
        label: 'Map Interaction',
        data: [5, 10, 15, 30, 35, 40, 50],
        borderColor: '#ff9800',
        fill: false
      },
      {
        label: 'UK Data Overlay',
        data: [8, 12, 20, 25, 30, 38, 45],
        borderColor: '#f44336',
        fill: false
      }
    ]
  };

  useEffect(() => {
    if (location.state) {
      if (location.state.purchasedFeatures) {
        setPurchasedFeatures(location.state.purchasedFeatures);
      }
      if (location.state.planName) {
        setPlanType(location.state.planName);
      }
    }
  }, [location.state]);

  // Handle plan selection and calculation
  // const handlePlanSelection = (plan) => {
  //   const totalPrice = planType === "month" ? plan.month * numUsers : plan.year * numUsers;
  //   setPurchasedFeatures(plan.features);
  //   navigate("/payment", {
  //     state: { selectedPlan: plan, totalPrice, purchasedFeatures: plan.features }
  //   });
  // };

  const purchasedFeatureCards = [
    {
      title: "Chatbot for Basic Queries",
      description: "An interactive chatbot that can assist with general inquiries, providing instant responses and automating support.",
      redirectLink: "/chatbot",
      image: chatbotImage, // Image for this feature
    },
    {
      title: "Chatbot with Map Integration",
      description: "Get live map data along with your chatbot responses, making it easier to visualize location-based queries and directions.",
      redirectLink: "/map-chatbot",
      image: mapIntegrationImage, // Image for this feature
    },
    {
      title: "Overlay UK Data",
      description: "Access detailed UK data overlays for better planning and decision-making, especially for regional insights and analysis.",
      redirectLink: "/uk-data",
      image: ukDataImage, // Image for this feature
    }
  ];
  


  const renderContent = () => {
    switch (selectedOption) {
      case "Overview":
        return (
          <div className="stats-container">
            {/* Left Section (Mini Cards) */}
            <div className="left-stats">
              <div className="mini-card">
                <h3>Total Users</h3>
                <p>{numUsers}</p>
              </div>
              <div className="mini-card">
                <h3>Chatbot Usage</h3>
                <p>{featureUsage.chatbot}%</p>
              </div>
              <div className="mini-card">
                <h3>Map Interaction Usage</h3>
                <p>{featureUsage.mapIntegration}%</p>
              </div>
              <div className="mini-card">
                <h3>UK Data Overlay Usage</h3>
                <p>{featureUsage.ukData}%</p>
              </div>
            </div>
  
            {/* Right Section (Graph and Pie Chart) */}
            <div className="right-stats">
              <div className="mini-graph">
                <Line data={lineChartData} />
              </div>
              <div className="pie-chart">
                <Doughnut data={pieChartData} />
              </div>
            </div>
          </div>
        );
      default:
        return <h2>Welcome to the Dashboard</h2>;
    }
  };
  
  

  return (
    <div className="subscription-container">
      {/* Sidebar */}
      <aside className="sidebar">
        <nav className="menu">
          <ul>
            {["Overview", "User Data", "CRUD"].map((option) => (
              <li key={option}>
                <button
                  className={`menu-item ${selectedOption === option ? "active" : ""}`}
                  onClick={() => setSelectedOption(option)}
                >
                  {option}
                </button>
              </li>
            ))}
          </ul>
        </nav>

        {/* User icon at the bottom of the sidebar */}
        <div className="profile-bottom">
          <div className="profile-info">
            <i className="fa fa-user profile-image"></i>
            <div>
              <h4>{userEmail.split("@")[0]}</h4>
              <p>Admin Account</p>
            </div>
          </div>
          <button className="logout-button">Logout</button>
        </div>
      </aside>

      {/* Main Content */}
      <div className={`main-content ${isChatbotPage ? 'no-padding' : ''}`}>
        {selectedOption === "Overview" && (
          <header className="header2">
            <h1>Welcome, {userEmail.split("@")[0]}</h1>
          </header>
        )}

        <div className="pricing-info">
          {selectedOption !== "Overview" && <h2>User Data</h2>}
        </div>

        {purchasedFeatures.length > 0 && selectedOption === "Overview" && (
          <div className="feature-cards-container">
            {/* Render purchased feature cards (if any) */}
            {purchasedFeatureCards.map((card, index) => {
              const isDisabled =
                planType === "Standard" && index !== 0;
              return (
                <div className={`feature-card ${isDisabled ? "disabled-card" : ""}`} key={index}>
                  <div className="feature-card-image">
                    <img src={card.image} alt={card.title} />
                  </div>
                  <div className="feature-card-content">
                    <h3 className="feature-card-title">{card.title}</h3>
                    <p className="feature-card-description">{card.description}</p>
                    <button
                      onClick={() => {
                        if (isDisabled) {
                          setPopupMessage("Upgrade to premium to use this functionality, Happy mapping!");
                        } else {
                          navigate(card.redirectLink);
                        }
                      }}
                      className={`use-tool-btn ${isDisabled ? "disabled-button" : ""}`}
                      disabled={isDisabled}
                    >
                      Use This Tool
                    </button>
                  </div>
                </div>
              );
            })}
          </div>
        )}

        {popupMessage && (
          <div className="popup-overlay">
            <div className="popup">
              <h3>{popupMessage}</h3>
              <button onClick={() => setPopupMessage("")} className="popup-btn">OK</button>
            </div>
          </div>
        )}

        {/* Dynamic Content */}
        <div className="dynamic-content">{renderContent()}</div>
      </div>
    </div>
  );
};

export default AdminDashboard;
